class Solution {
public:
    int longestSemiRepetitiveSubstring(string s) {
        int n = s.size();
        int res = 0;
        for (int i = 0; i < n; i++) {
            int cnt = 1;
            for (int j = i + 2; j < n; j += 2) {
                if (s[j] == s[j - 1] && s[j] == s[j - 2]) {
                    break;
                }
                if (s[j] == s[j - 1]) {
                    cnt++;
                }
            }
            res = max(res, cnt);
        }
        return res;
    }
};
```

